// ServerInterface represents all server handlers.
type ServerInterface interface {
	// Exchange a magic-link token for a portal token pair
	// (POST /api/auth/magic-link/exchange)
	ExchangeMagicLink(w http.ResponseWriter, r *http.Request)
	// Request a magic-link sign-in email
	// (POST /api/auth/magic-link/request)
	RequestMagicLink(w http.ResponseWriter, r *http.Request)
	// Exchange OAuth authorization code for a portal token pair
	// (POST /api/auth/oauth/callback)
	OauthCallback(w http.ResponseWriter, r *http.Request)
	// Begin OAuth authorization flow — returns the provider authorize URL
	// (POST /api/auth/oauth/start)
	StartOAuth(w http.ResponseWriter, r *http.Request)
	// Exchange a refresh token for a new access+refresh pair
	// (POST /api/auth/refresh)
	RefreshToken(w http.ResponseWriter, r *http.Request)
	// Revoke a token (or all tokens for the account)
	// (POST /api/auth/revoke)
	RevokeToken(w http.ResponseWriter, r *http.Request)
	// Return the authenticated account's profile and org memberships
	// (GET /api/me)
	GetMe(w http.ResponseWriter, r *http.Request)
	// Create a new org; the authenticated account becomes its creator
	// (POST /api/orgs)
	CreateOrg(w http.ResponseWriter, r *http.Request)
	// Create an org invite (requires creator role); sends email to recipient
	// (POST /api/orgs/{orgID}/invites)
	CreateOrgInvite(w http.ResponseWriter, r *http.Request, orgID string)
	// Accept a pending org invite (requires Bearer; verifies token + recipient email)
	// (POST /api/orgs/{orgID}/invites/{inviteID}/accept)
	AcceptOrgInvite(w http.ResponseWriter, r *http.Request, orgID string, inviteID string)
	// List members of an org (requires creator or member role)
	// (GET /api/orgs/{orgID}/members)
	ListOrgMembers(w http.ResponseWriter, r *http.Request, orgID string)
	// List sessions visible to the caller (active + recent), cursor-paginated
	// (GET /api/orgs/{orgID}/sessions)
	ListSessions(w http.ResponseWriter, r *http.Request, orgID string, params ListSessionsParams)
	// Create a new session in the org; the authenticated account becomes the creator
	// (POST /api/orgs/{orgID}/sessions)
	CreateSession(w http.ResponseWriter, r *http.Request, orgID string)
	// Get a session's metadata and member list
	// (GET /api/orgs/{orgID}/sessions/{sessionID})
	GetSession(w http.ResponseWriter, r *http.Request, orgID string, sessionID string)
	// Update goal, scope (widening only), or default_mode; creator only
	// (PATCH /api/orgs/{orgID}/sessions/{sessionID})
	PatchSession(w http.ResponseWriter, r *http.Request, orgID string, sessionID string)
	// Abandon the session without finalizing; sets status=ended, end_reason=abandoned; creator only
	// (POST /api/orgs/{orgID}/sessions/{sessionID}/abandon)
	AbandonSession(w http.ResponseWriter, r *http.Request, orgID string, sessionID string)
	// List comments in a session, cursor-paginated, with optional filters
	// (GET /api/orgs/{orgID}/sessions/{sessionID}/comments)
	ListComments(w http.ResponseWriter, r *http.Request, orgID string, sessionID string, params ListCommentsParams)
	// Create a new comment anchored to a commit in the session
	// (POST /api/orgs/{orgID}/sessions/{sessionID}/comments)
	CreateComment(w http.ResponseWriter, r *http.Request, orgID string, sessionID string)
	// Mark a comment as resolved with an optional resolution note
	// (POST /api/orgs/{orgID}/sessions/{sessionID}/comments/{commentId}/resolve)
	ResolveComment(w http.ResponseWriter, r *http.Request, orgID string, sessionID string, commentId string)
	// Assembled turn-start digest for additionalContext injection
	// (GET /api/orgs/{orgID}/sessions/{sessionID}/digest)
	GetSessionDigest(w http.ResponseWriter, r *http.Request, orgID string, sessionID string, params GetSessionDigestParams)
	// Fetch file content at a specific commit
	// (GET /api/orgs/{orgID}/sessions/{sessionID}/files)
	GetSessionFile(w http.ResponseWriter, r *http.Request, orgID string, sessionID string, params GetSessionFileParams)
	// Transition session to finalizing; idempotent if already finalizing
	// (POST /api/orgs/{orgID}/sessions/{sessionID}/finalize)
	FinalizeSession(w http.ResponseWriter, r *http.Request, orgID string, sessionID string)
	// Invite a user to a session by email; sends a magic-link-style join email
	// (POST /api/orgs/{orgID}/sessions/{sessionID}/invites)
	InviteToSession(w http.ResponseWriter, r *http.Request, orgID string, sessionID string)
	// Accept a session invite; binds the caller to the session as a member
	// (POST /api/orgs/{orgID}/sessions/{sessionID}/invites/{inviteID}/accept)
	AcceptSessionInvite(w http.ResponseWriter, r *http.Request, orgID string, sessionID string, inviteID string)
	// Remove a member from a session; creator only
	// (POST /api/orgs/{orgID}/sessions/{sessionID}/members/{accountID}/remove)
	RemoveSessionMember(w http.ResponseWriter, r *http.Request, orgID string, sessionID string, accountID string)
	// Upsert the collaboration mode for a specific ref
	// (POST /api/orgs/{orgID}/sessions/{sessionID}/ref-modes)
	UpsertRefMode(w http.ResponseWriter, r *http.Request, orgID string, sessionID string)
	// List all refs in the session bare repository with mode and tip SHA
	// (GET /api/orgs/{orgID}/sessions/{sessionID}/refs)
	ListSessionRefs(w http.ResponseWriter, r *http.Request, orgID string, sessionID string)
}

